     * Edit a message.
     */
    func editMessage(channelId: String, eventId: String, content: String) async throws 
    
    /**
     * Export the private key as bech32-encoded nsec.
     */
    func exportNsec() throws  -> String
    
    /**
     * Get details for a single channel.
     */
    func getChannel(channelId: String) async throws  -> Channel
    
    /**
     * Get the personalized home feed.
     */
    func getFeed() async throws  -> HomeFeed
    
    /**
     * Get a user's profile by pubkey.
     */
    func getProfile(pubkey: String) async throws  -> UserProfile
    
    /**
     * Batch-fetch multiple user profiles.
     */
    func getProfilesBatch(pubkeys: [String]) async throws  -> [UserProfile]
    
    /**
     * Fetch a full thread by root event ID.
     */
    func getThread(channelId: String, rootEventId: String) async throws  -> [Message]
    
    /**
     * Join a channel.
     */
    func joinChannel(channelId: String) async throws 
    
    /**
     * Leave a channel.
     */
    func leaveChannel(channelId: String) async throws 
    
    /**
     * List channels accessible to the current user.
     */
    func listChannels(filter: ChannelFilter) async throws  -> [Channel]
    
    /**
     * List DM conversations.
     */
    func listDms() async throws  -> [DmConversation]
    
    /**
     * List members of a channel.
     */
    func listMembers(channelId: String) async throws  -> [ChannelMember]
    
    /**
     * List messages in a channel with optional cursor-based pagination.
     */
    func listMessages(channelId: String, before: Int64?, limit: UInt32?) async throws  -> MessagePage
    
    /**
     * Authenticate with a Nostr private key (nsec bech32 or 64-char hex).
     */
    func loginWithKey(nsecOrHex: String) async throws  -> UserIdentity
    
    /**
     * Authenticate with a pre-existing API token.
     */
    func loginWithToken(apiToken: String) async throws  -> UserIdentity
    
    /**
     * Open or create a DM conversation with the given participants.
     */
    func openDm(pubkeys: [String]) async throws  -> DmConversation
    
    /**
     * Remove a reaction.
     */
    func removeReaction(reactionEventId: String) async throws 
    
    /**
     * Full-text search across messages.
     */
    func search(query: String) async throws  -> [SearchResult]
    
    /**
     * Search users by name or pubkey prefix.
     */
    func searchUsers(query: String) async throws  -> [UserProfile]
    
    /**
     * Send a message to a channel.
     */
    func sendMessage(params: SendMessageParams) async throws  -> Message
    
    /**
     * Register a listener for push events from the relay.
     */
    func setEventListener(listener: SproutEventListener) 
    
    /**
     * Set the current user's presence status.
     */
    func setPresence(status: PresenceStatus) async throws 
    
    /**
     * Subscribe to real-time events for a channel. Returns a subscription ID.
