    /**
     * Update the current user's profile.
     */
    func updateProfile(params: UpdateProfileParams) async throws 
    
    /**
     * Upload media bytes and return the Blossom blob descriptor.
     */
    func uploadMedia(fileBytes: Data, mimeType: String) async throws  -> MediaUploadResult
    
