#if swift(>=5.8)
@_documentation(visibility: private)
#endif
public struct FfiConverterTypeSproutClient: FfiConverter {

    typealias FfiType = UnsafeMutableRawPointer
    typealias SwiftType = SproutClient

    public static func lift(_ pointer: UnsafeMutableRawPointer) throws -> SproutClient {
        return SproutClient(unsafeFromRawPointer: pointer)
    }

    public static func lower(_ value: SproutClient) -> UnsafeMutableRawPointer {
        return value.uniffiClonePointer()
    }

    public static func read(from buf: inout (data: Data, offset: Data.Index)) throws -> SproutClient {
        let v: UInt64 = try readInt(&buf)
        // The Rust code won't compile if a pointer won't fit in a UInt64.
        // We have to go via `UInt` because that's the thing that's the size of a pointer.
        let ptr = UnsafeMutableRawPointer(bitPattern: UInt(truncatingIfNeeded: v))
        if (ptr == nil) {
            throw UniffiInternalError.unexpectedNullPointer
        }
        return try lift(ptr!)
    }

    public static func write(_ value: SproutClient, into buf: inout [UInt8]) {
        // This fiddling is because `Int` is the thing that's the same size as a pointer.
        // The Rust code won't compile if a pointer won't fit in a `UInt64`.
        writeInt(&buf, UInt64(bitPattern: Int64(Int(bitPattern: lower(value)))))
    }
}


#if swift(>=5.8)
@_documentation(visibility: private)
#endif
public func FfiConverterTypeSproutClient_lift(_ pointer: UnsafeMutableRawPointer) throws -> SproutClient {
    return try FfiConverterTypeSproutClient.lift(pointer)
}

#if swift(>=5.8)
@_documentation(visibility: private)
#endif
public func FfiConverterTypeSproutClient_lower(_ value: SproutClient) -> UnsafeMutableRawPointer {
    return FfiConverterTypeSproutClient.lower(value)
}




/**
 * A Sprout channel.
 */
public struct Channel {
    /**
     * Channel UUID.
     */
    public var id: String
    /**
     * Channel name.
     */
    public var name: String
    /**
     * Channel description/about.
     */
    public var about: String?
    /**
     * Current topic.
     */
    public var topic: String?
    /**
     * Channel type.
     */
    public var channelType: ChannelType
    /**
     * Visibility setting.
     */
    public var visibility: ChannelVisibility
    /**
     * Number of members.
     */
    public var memberCount: UInt32
    /**
     * Timestamp of the last message (Unix seconds), if any.
     */
    public var lastMessageAt: Int64?
    /**
     * Whether the current user is a member.
     */
    public var isMember: Bool

    // Default memberwise initializers are never public by default, so we
    // declare one manually.
    public init(
        /**
         * Channel UUID.
         */id: String, 
        /**
         * Channel name.
         */name: String, 
        /**
         * Channel description/about.
         */about: String?, 
        /**
         * Current topic.
         */topic: String?, 
        /**
         * Channel type.
         */channelType: ChannelType, 
        /**
         * Visibility setting.
         */visibility: ChannelVisibility, 
        /**
         * Number of members.
         */memberCount: UInt32, 
        /**
         * Timestamp of the last message (Unix seconds), if any.
         */lastMessageAt: Int64?, 
        /**
         * Whether the current user is a member.
         */isMember: Bool) {
        self.id = id
        self.name = name
        self.about = about
        self.topic = topic
        self.channelType = channelType
        self.visibility = visibility
        self.memberCount = memberCount
        self.lastMessageAt = lastMessageAt
        self.isMember = isMember
    }
}

#if compiler(>=6)
extension Channel: Sendable {}
#endif


extension Channel: Equatable, Hashable {
    public static func ==(lhs: Channel, rhs: Channel) -> Bool {
        if lhs.id != rhs.id {
            return false
        }
        if lhs.name != rhs.name {
            return false
        }
        if lhs.about != rhs.about {
            return false
        }
        if lhs.topic != rhs.topic {
            return false
        }
        if lhs.channelType != rhs.channelType {
            return false
        }
        if lhs.visibility != rhs.visibility {
            return false
        }
        if lhs.memberCount != rhs.memberCount {
            return false
        }
        if lhs.lastMessageAt != rhs.lastMessageAt {
            return false
        }
        if lhs.isMember != rhs.isMember {
            return false
        }
        return true
    }

    public func hash(into hasher: inout Hasher) {
        hasher.combine(id)
        hasher.combine(name)
        hasher.combine(about)
        hasher.combine(topic)
        hasher.combine(channelType)
        hasher.combine(visibility)
        hasher.combine(memberCount)
        hasher.combine(lastMessageAt)
