/**
 * WebSocket connection state.
 */

public enum ConnectionState {
    
    /**
     * Not connected to any relay.
     */
    case disconnected
    /**
     * TCP/TLS handshake in progress.
     */
    case connecting
    /**
     * NIP-42 authentication in progress.
     */
    case authenticating
    /**
     * Fully connected and authenticated.
     */
    case connected
    /**
     * Reconnecting after a connection drop.
     */
    case reconnecting(
        /**
         * Number of reconnect attempts so far.
         */attempt: UInt32
    )
}


#if compiler(>=6)
extension ConnectionState: Sendable {}
#endif

#if swift(>=5.8)
@_documentation(visibility: private)
#endif
public struct FfiConverterTypeConnectionState: FfiConverterRustBuffer {
    typealias SwiftType = ConnectionState

    public static func read(from buf: inout (data: Data, offset: Data.Index)) throws -> ConnectionState {
        let variant: Int32 = try readInt(&buf)
        switch variant {
        
        case 1: return .disconnected
        
        case 2: return .connecting
        
        case 3: return .authenticating
        
        case 4: return .connected
        
        case 5: return .reconnecting(attempt: try FfiConverterUInt32.read(from: &buf)
        )
        
        default: throw UniffiInternalError.unexpectedEnumCase
        }
    }

    public static func write(_ value: ConnectionState, into buf: inout [UInt8]) {
        switch value {
        
        
        case .disconnected:
            writeInt(&buf, Int32(1))
        
        
        case .connecting:
            writeInt(&buf, Int32(2))
        
        
        case .authenticating:
            writeInt(&buf, Int32(3))
        
        
        case .connected:
            writeInt(&buf, Int32(4))
        
        
        case let .reconnecting(attempt):
            writeInt(&buf, Int32(5))
            FfiConverterUInt32.write(attempt, into: &buf)
            
        }
    }
}


