        let variant: Int32 = try readInt(&buf)
        switch variant {

        

        
        case 1: return .NotConnected(
            message: try FfiConverterString.read(from: &buf)
        )
        
        case 2: return .AuthRequired(
            message: try FfiConverterString.read(from: &buf)
        )
        
        case 3: return .AuthFailed(
            message: try FfiConverterString.read(from: &buf)
        )
        
        case 4: return .TokenExpired(
            message: try FfiConverterString.read(from: &buf)
        )
        
        case 5: return .InvalidKey(
            message: try FfiConverterString.read(from: &buf)
        )
        
        case 6: return .RelayError(
            message: try FfiConverterString.read(from: &buf)
        )
        
        case 7: return .NetworkError(
            message: try FfiConverterString.read(from: &buf)
        )
        
        case 8: return .WebSocketError(
            message: try FfiConverterString.read(from: &buf)
        )
        
        case 9: return .NotFound(
            message: try FfiConverterString.read(from: &buf)
        )
        
        case 10: return .PermissionDenied(
            message: try FfiConverterString.read(from: &buf)
        )
        
        case 11: return .ValidationError(
            message: try FfiConverterString.read(from: &buf)
        )
        
        case 12: return .StorageError(
            message: try FfiConverterString.read(from: &buf)
        )
        
        case 13: return .InternalError(
            message: try FfiConverterString.read(from: &buf)
        )
        

        default: throw UniffiInternalError.unexpectedEnumCase
        }
